import{_ as e,o as l,c as t,a3 as r}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"消息列表与悬浮操作栏","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/messages/message-list.md","filePath":"user-guide/tools/llm-chat/messages/message-list.md","lastUpdated":1778239080000}'),s={name:"user-guide/tools/llm-chat/messages/message-list.md"};function o(i,a,n,g,h,d){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="消息列表与悬浮操作栏" tabindex="-1">消息列表与悬浮操作栏 <a class="header-anchor" href="#消息列表与悬浮操作栏" aria-label="Permalink to &quot;消息列表与悬浮操作栏&quot;">​</a></h1><p>消息列表是对话的主战场。系统为每条消息提供了丰富的交互功能，通过悬浮操作栏即可快速触发。</p><h2 id="_1-悬浮操作栏-message-toolbar" tabindex="-1">1. 悬浮操作栏 (Message Toolbar) <a class="header-anchor" href="#_1-悬浮操作栏-message-toolbar" aria-label="Permalink to &quot;1. 悬浮操作栏 (Message Toolbar)&quot;">​</a></h2><p>将鼠标悬停在任意消息卡片上，底部会弹出操作栏：</p><h3 id="常用操作" tabindex="-1">常用操作 <a class="header-anchor" href="#常用操作" aria-label="Permalink to &quot;常用操作&quot;">​</a></h3><ul><li><strong>📋 复制</strong>: 复制消息原文（Markdown 或纯文本）。</li><li><strong>✏️ 编辑</strong>: 进入编辑模式。</li><li><strong>🔗 创建分支</strong>: 在当前节点开启平行对话路径。</li><li><strong>🔄 重新生成</strong>: 让 AI 重新生成此条回复（可快速切换模型重试）。</li><li><strong>👁️ 启用/禁用</strong>: 切换该消息是否参与上下文组装。禁用的消息会变灰，且不会发送给 LLM。</li><li><strong>🌐 翻译</strong>: 实时翻译消息内容。按住 <code>Shift</code> 点击可快速触发默认翻译。</li></ul><h3 id="更多菜单-···" tabindex="-1">更多菜单 (<code>···</code>) <a class="header-anchor" href="#更多菜单-···" aria-label="Permalink to &quot;更多菜单 (`···`)&quot;">​</a></h3><ul><li><strong>⏩ 续写</strong>: 让 AI 从当前内容的末尾继续生成。</li><li><strong>📊 上下文分析</strong>: 查看该特定消息在当前上下文管道中的处理状态。</li><li><strong>📥 导出</strong>: 导出该消息所在的分支。</li><li><strong>🔢 重新计算 Token</strong>: 强制更新该消息的 Token 统计。</li><li><strong>🗄️ 数据编辑</strong>: 进入<a href="./message-data-editor">高级数据编辑器</a>。</li></ul><h2 id="_2-编辑模式与分支策略" tabindex="-1">2. 编辑模式与分支策略 <a class="header-anchor" href="#_2-编辑模式与分支策略" aria-label="Permalink to &quot;2. 编辑模式与分支策略&quot;">​</a></h2><p>当你点击 ✏️ 编辑按钮时，系统提供两种保存方式：</p><ol><li><strong>保存修改 (Overwrite)</strong>: 直接覆盖当前节点。 <ul><li><em>适用场景</em>: 修正错别字，或修改尚未产生子节点的最新消息。</li></ul></li><li><strong>保存并创建新分支 (Branch)</strong>: <ul><li><em>适用场景</em>: 修改已发送的消息，并希望基于新内容开启一段新的对话，同时保留旧的对话路径。</li><li><em>默认行为</em>: 编辑已发送的用户消息时，系统通常会自动采用分支策略。</li></ul></li></ol><h2 id="_3-原生虚拟渲染技术" tabindex="-1">3. 原生虚拟渲染技术 <a class="header-anchor" href="#_3-原生虚拟渲染技术" aria-label="Permalink to &quot;3. 原生虚拟渲染技术&quot;">​</a></h2><p>为了确保在包含数千条消息的长对话中依然保持丝滑滚动，系统采用了<strong>原生虚拟渲染</strong>：</p><ul><li><strong>按需渲染</strong>: 仅渲染视口内的消息，大幅降低内存占用。</li><li><strong>位置保持</strong>: 切换分支或重新进入会话时，系统会自动定位到你上次浏览的精确行。</li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../sessions/tree-graph">对话树图视图</a></li><li><a href="./message-data-editor">会话数据管理</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a></li></ul>',17)])])}const m=e(s,[["render",o]]);export{c as __pageData,m as default};
